/* --- Statement parsing --- */

void parse_compound_stmt(void) {
    expect(TOK_BEGIN);
    parse_stmt();
    while (tok_type == TOK_SEMI) {
        next_token();
        parse_stmt();
    }
    expect(TOK_END);
