void parse_if_stmt(void) {
    int type;
    int l_else;
    int l_end;

    next_token(); /* consume IF */
    type = parse_expression();
    if (type != TYPE_BOOLEAN) error("if condition must be boolean");

    l_else = new_label();
    l_end = new_label();

    printf("    jz L%d\n", l_else);

    expect(TOK_THEN);
    parse_stmt();

    if (tok_type == TOK_ELSE) {
        printf("    jmp L%d\n", l_end);
        printf("L%d:\n", l_else);
        next_token();
        parse_stmt();
        printf("L%d:\n", l_end);
    } else {
        printf("L%d:\n", l_else);
    }
