void parse_while_stmt(void) {
    int type;
    int l_start;
    int l_end;

    next_token(); /* consume WHILE */
    l_start = new_label();
    l_end = new_label();

    printf("L%d:\n", l_start);

    type = parse_expression();
    if (type != TYPE_BOOLEAN) error("while condition must be boolean");

    printf("    jz L%d\n", l_end);

    expect(TOK_DO);
    parse_stmt();

    printf("    jmp L%d\n", l_start);
    printf("L%d:\n", l_end);
