/* Forward declarations for recursive descent */
int parse_expression(void);
void parse_stmt(void);

/* --- String helpers --- */

void str_copy(char *dst, char *src) {
    int i;
    i = 0;
    while (src[i] != 0) {
        dst[i] = src[i];
        i = i + 1;
    }
