void error(char *msg) {
    printf("error line %d: %s (got %s)\n", tok_line, msg, token_name(tok_type));
    parse_error = 1;
}

void expect(int tok) {
    if (tok_type != tok) {
        printf("error line %d: expected %s, got %s '%s'\n",
               tok_line, token_name(tok), token_name(tok_type), tok_lexeme);
        parse_error = 1;
        return;
    }
    next_token();
}

int accept(int tok) {
    if (tok_type == tok) {
        next_token();
        return 1;
    }
    return 0;
}

