int new_label(void) {
    int l;
    l = label_count;
    label_count = label_count + 1;
    return l;
}

/* --- Symbol table --- */

char *sym_name_at(int i) {
    return &sym_name[i * MAX_NAME];
}

int sym_lookup(char *name) {
    int i;
    i = 0;
    while (i < sym_count) {
        if (strcmp(sym_name_at(i), name) == 0) return i;
        i = i + 1;
    }
    return -1;
}

int sym_add(char *name, int kind, int type, int value) {
    int idx;
