        printf("error line %d: duplicate symbol '%s'\n", tok_line, name);
        parse_error = 1;
        return -1;
    }
    if (sym_count >= MAX_SYMBOLS) {
        error("too many symbols");
        return -1;
    }
    idx = sym_count;
    str_copy(sym_name_at(idx), name);
    sym_kind[idx] = kind;
    sym_type_id[idx] = type;
    sym_value[idx] = value;
    sym_count = sym_count + 1;
    return idx;
}

