int parse_factor(void) {
    int idx;
    int type;
    char name[MAX_NAME];

    if (tok_type == TOK_INT_LIT) {
        printf("    push %d\n", tok_int_val);
        next_token();
        return TYPE_INTEGER;
    }

    if (tok_type == TOK_TRUE) {
        printf("    push 1\n");
        next_token();
        return TYPE_BOOLEAN;
    }

